"use client";

import type { ReactNode } from "react";
import type { RadioGroupProps } from "react-aria-components";
import { Label as AriaLabel, Radio as AriaRadio, RadioGroup as AriaRadioGroup, Text as AriaText } from "react-aria-components";
import { Button } from "@/components/atoms/Button/BaseButton";
import { CheckboxBase } from "@/vendor/untitled-ui/base/checkbox/checkbox";
import { cx } from "@/utils/cx";
import { WithDataId } from "@/types/withDataId";

interface PaymentCardItemType {
    value: string;
    title: string;
    description: string;
    logo: ReactNode;
    disabled?: boolean;
}

interface RadioGroupPaymentIconProps extends RadioGroupProps, WithDataId {
    size?: "sm";
    items: PaymentCardItemType[];
}

export const RadioGroupPaymentIcon = ({ items, size = "sm", className, 'data-id': dataId,  ...props }: RadioGroupPaymentIconProps) => {
    return (
        <AriaRadioGroup {...props} className={(state) => cx("flex flex-col gap-3", typeof className === "function" ? className(state) : className)}>
            {items.map((card) => (
                <AriaRadio
                    isDisabled={card.disabled}
                    key={card.value}
                    value={card.value}
                    className={({ isDisabled, isSelected, isFocusVisible }) =>
                        cx(
                            "relative flex cursor-pointer items-start gap-1 rounded-xl bg-primary p-4 outline-focus-ring ring-inset",
                            isSelected ? "ring-2 ring-brand" : "ring-1 ring-secondary",
                            isDisabled && "cursor-not-allowed bg-disabled_subtle ring-disabled_subtle",
                            isFocusVisible && "outline-2 outline-offset-2",
                        )
                    }
                >
                    {({ isDisabled, isSelected, isFocusVisible }) => (
                        <>
                            <div className={cx("flex flex-1 gap-3")}>
                                <span className="shrink-0">{card.logo}</span>
                                <div>
                                    <div className={cx("flex flex-col")}>
                                        <AriaLabel
                                            className={cx("pointer-events-none text-secondary text-sm font-medium")}
                                        >
                                            {card.title}
                                        </AriaLabel>
                                        <AriaText slot="description" className={cx("text-tertiary text-sm")}>
                                            {card.description}
                                        </AriaText>
                                    </div>
                                    <div className={cx("flex gap-3 mt-2")}>
                                        <Button color="link-gray" size="sm" isDisabled={isDisabled} data-id={`${dataId}-setAsDefaultButton`}>
                                            Set as default
                                        </Button>
                                        <Button color="link-color" size="sm" isDisabled={isDisabled} data-id={`${dataId}-editButton`}>
                                            Edit
                                        </Button>
                                    </div>
                                </div>
                            </div>

                            <CheckboxBase size="sm" isDisabled={isDisabled} isSelected={isSelected} isFocusVisible={isFocusVisible} data-id={`${dataId}-checkbox-${card.value}`}/>
                        </>
                    )}
                </AriaRadio>
            ))}
        </AriaRadioGroup>
    );
};
